// OK: unwrap in tests
#[cfg(test)]
mod tests {
    #[test]
    fn test_something() {
        let result = do_something();
        let value = result.unwrap(); // acceptable in tests
        assert_eq!(value, expected);
    }
}

// OK: expect for env vars that must be set at startup
fn main() {
    let config_path = std::env::var("CONFIG_PATH")
        .expect("CONFIG_PATH environment variable must be set");
}
